-- FIFA World Cup 2026 squad players seed
-- Source: https://fdp.fifa.org/assetspublic/ce281/pdf/SquadLists-English.pdf
-- Source version in PDF: Version 1 - 2026-06-04 20:57 UTC
-- Parsed rows: 1248 players / 48 teams

create table if not exists public.world_cup_players (
  id text primary key,
  team_name text not null,
  team_code text not null,
  squad_no integer not null,
  position text not null check (position in ('GK', 'DF', 'MF', 'FW')),
  display_name text not null,
  shirt_name text,
  raw_name text,
  dob date,
  club text,
  height_cm integer,
  source_page integer,
  source_version text not null default 'Version 1 - 2026-06-04 20:57 UTC',
  source_url text not null default 'https://fdp.fifa.org/assetspublic/ce281/pdf/SquadLists-English.pdf',
  updated_at timestamptz not null default now(),
  unique (team_code, squad_no)
);

alter table public.world_cup_players enable row level security;

drop policy if exists "world cup players are readable by everyone" on public.world_cup_players;
create policy "world cup players are readable by everyone"
on public.world_cup_players for select
to anon, authenticated
using (true);

on conflict (id) do update set
  team_name = excluded.team_name,
  team_code = excluded.team_code,
  squad_no = excluded.squad_no,
  position = excluded.position,
  display_name = excluded.display_name,
  shirt_name = excluded.shirt_name,
  raw_name = excluded.raw_name,
  dob = excluded.dob,
  club = excluded.club,
  height_cm = excluded.height_cm,
  source_page = excluded.source_page,
  source_version = excluded.source_version,
  source_url = excluded.source_url,
  updated_at = now();
